script:
frappe.ui.form.on("Trip", {
    validate(frm) {
        if (
            frm.doc.allow_reassignment &&
            (!frm.doc.reassignment_reason || frm.doc.reassignment_reason.length < 10)
        ) {
            frappe.throw("Please provide a valid reason for reassignment");
        }
    }
});

frappe.ui.form.on("TRIP", {
    vehicle(frm) {

        if (!frm.doc.vehicle) {
            frm.set_value("driver", null);
            frm.set_df_property("driver", "read_only", 0);
            return;
        }

        frappe.db.get_value(
            "TMS VEHICLE",
            frm.doc.vehicle,
            "assigned_driver"
        ).then(r => {

            if (r.message && r.message.assigned_driver) {
                frm.set_value("driver", r.message.assigned_driver);
                frm.set_df_property("driver", "read_only", 1);
            } else {
                frm.set_df_property("driver", "read_only", 0);
            }
        });
    }
});

frappe.ui.form.on("BILLING BATCH", {
    get_trips(frm) {

        if (!frm.doc.customer) {
            frappe.msgprint("Please select Customer first");
            return;
        }

        frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "TRIP",
                filters: {
                    customer: frm.doc.customer,
                    trip_status: "Completed",
                    billing_status: "Not Billed"
                },
                fields: ["name", "freight_amount"]
            },
            callback(r) {

                frm.clear_table("billing_batch_trip");

                r.message.forEach(t => {
                    let row = frm.add_child("billing_batch_trip");
                    row.trip_billing = t.name;
                    row.freight_amount = t.freight_amount || 0;
                    row.other_charges = 0;
                    row.total = t.freight_amount || 0;
                });

                frm.refresh_field("billing_batch_trip");
            }
        });
    }
});

frappe.ui.form.on("Billing Batch Trip", {
    freight_amount(frm, cdt, cdn) {
        calculate_total(cdt, cdn);
    },
    other_charges(frm, cdt, cdn) {
        calculate_total(cdt, cdn);
    }
});

function calculate_total(cdt, cdn) {
    let row = locals[cdt][cdn];
    row.total = (row.freight_amount || 0) + (row.other_charges || 0);
}

frappe.ui.form.on('TRIP', {
    refresh(frm) {
        calculate_advances(frm);
        calculate_expenses(frm);
        calculate_settlement(frm);
    },

    trip_advances_add: function(frm) {
        calculate_advances(frm);
        calculate_settlement(frm);
    },
    trip_advances_remove: function(frm) {
        calculate_advances(frm);
        calculate_settlement(frm);
    },

    trip_expenses_add: function(frm) {
        calculate_expenses(frm);
        calculate_settlement(frm);
    },
    trip_expenses_remove: function(frm) {
        calculate_expenses(frm);
        calculate_settlement(frm);
    }
});

// 🔹 ADVANCE + BILLING LOGIC (FINAL)
function calculate_advances(frm) {
    let trip_advance = 0;      // reduces freight
    let company_received = 0;  // accounting
    let driver_received = 0;   // settlement

    (frm.doc.trip_advances || []).forEach(row => {
        let amt = row.amount || 0;

        // Any customer/client payment = trip advance
        if (["Customer", "Client"].includes(row.paid_by)) {
            trip_advance += amt;
        }

        // Company cash actually received
        if (row.received_by === "Company") {
            company_received += amt;
        }

        // Driver received money (company or customer)
        if (row.received_by === "Driver") {
            driver_received += amt;
        }
    });

    frm.set_value("trip_advance_total", trip_advance);
    frm.set_value("company_advance_received", company_received);
    frm.set_value("driver_advance", driver_received);

    let freight = frm.doc.freight_amount || 0;
    let due = freight - trip_advance;

    frm.set_value("due_balance", due);

    // Payment status
    if (due > 0 && trip_advance === 0) {
        frm.set_value("payment_status", "Unpaid");
    } else if (due > 0 && trip_advance > 0) {
        frm.set_value("payment_status", "Partially Paid");
    } else if (due === 0) {
        frm.set_value("payment_status", "Paid");
    } else if (due < 0) {
        frm.set_value("payment_status", "Overpaid");
    }
}

// 🔹 EXPENSE LOGIC (UNCHANGED, CORRECT)
function calculate_expenses(frm) {
    let driver_exp = 0;
    let vehicle_exp = 0;

    (frm.doc.trip_expenses || []).forEach(row => {
        if (row.expense_category === "Driver") {
            driver_exp += row.amount || 0;
        }
        if (row.expense_category === "Vehicle") {
            vehicle_exp += row.amount || 0;
        }
    });

    frm.set_value("total_driver_expense", driver_exp);
    frm.set_value("total_vehicle_expense", vehicle_exp);
    frm.set_value("driver_expense", driver_exp);
}

// 🔹 DRIVER SETTLEMENT (FINAL)
function calculate_settlement(frm) {
    let net = (frm.doc.driver_advance || 0) - (frm.doc.driver_expense || 0);
    frm.set_value("net_settlement", net);
}
